#!/bin/python3

import socket



sock = socket.socket(socket.AF_INET , socket.SOCK_STREAM)
sock.connect(("127.0.0.0" , 1111))

while True:
           
           data = ""
           n = sock.send(data.encode())
           print(f'{n} bytes sent')
           if len(data) == n:
              break
  
             
